// ControllerServer is the server API for Controller service.
// All implementations must embed UnimplementedControllerServer
// for forward compatibility.
//
// Controller service - orchestrates VMs across nodes
type ControllerServer interface {
	// Node registration and heartbeat
	RegisterNode(context.Context, *RegisterNodeRequest) (*RegisterNodeResponse, error)
	Heartbeat(context.Context, *HeartbeatRequest) (*HeartbeatResponse, error)
	SyncVmState(context.Context, *SyncVmStateRequest) (*SyncVmStateResponse, error)
	SyncWorkloadState(context.Context, *SyncWorkloadStateRequest) (*SyncWorkloadStateResponse, error)
	// VM operations (declarative desired-state API managed by controller)
	CreateVm(context.Context, *CreateVmRequest) (*CreateVmResponse, error)
	UpdateVm(context.Context, *UpdateVmRequest) (*UpdateVmResponse, error)
	DeleteVm(context.Context, *DeleteVmRequest) (*DeleteVmResponse, error)
	SetVmDesiredState(context.Context, *SetVmDesiredStateRequest) (*SetVmDesiredStateResponse, error)
	GetVm(context.Context, *GetVmRequest) (*GetVmResponse, error)
	ListVms(context.Context, *ListVmsRequest) (*ListVmsResponse, error)
	CreateWorkload(context.Context, *CreateWorkloadRequest) (*CreateWorkloadResponse, error)
	DeleteWorkload(context.Context, *DeleteWorkloadRequest) (*DeleteWorkloadResponse, error)
	SetWorkloadDesiredState(context.Context, *SetWorkloadDesiredStateRequest) (*SetWorkloadDesiredStateResponse, error)
	GetWorkload(context.Context, *GetWorkloadRequest) (*GetWorkloadResponse, error)
	ListWorkloads(context.Context, *ListWorkloadsRequest) (*ListWorkloadsResponse, error)
	CreateNetwork(context.Context, *CreateNetworkRequest) (*CreateNetworkResponse, error)
	DeleteNetwork(context.Context, *DeleteNetworkRequest) (*DeleteNetworkResponse, error)
	ListNetworks(context.Context, *ListNetworksRequest) (*ListNetworksResponse, error)
	CreateSecurityGroup(context.Context, *CreateSecurityGroupRequest) (*CreateSecurityGroupResponse, error)
	GetSecurityGroup(context.Context, *GetSecurityGroupRequest) (*GetSecurityGroupResponse, error)
	ListSecurityGroups(context.Context, *ListSecurityGroupsRequest) (*ListSecurityGroupsResponse, error)
	DeleteSecurityGroup(context.Context, *DeleteSecurityGroupRequest) (*DeleteSecurityGroupResponse, error)
	AttachSecurityGroup(context.Context, *AttachSecurityGroupRequest) (*AttachSecurityGroupResponse, error)
	DetachSecurityGroup(context.Context, *DetachSecurityGroupRequest) (*DetachSecurityGroupResponse, error)
	// Node operations
	ListNodes(context.Context, *ListNodesRequest) (*ListNodesResponse, error)
	GetNode(context.Context, *GetNodeRequest) (*GetNodeResponse, error)
	// SSH key management
	CreateSshKey(context.Context, *CreateSshKeyRequest) (*CreateSshKeyResponse, error)
	DeleteSshKey(context.Context, *DeleteSshKeyRequest) (*DeleteSshKeyResponse, error)
	ListSshKeys(context.Context, *ListSshKeysRequest) (*ListSshKeysResponse, error)
	GetSshKey(context.Context, *GetSshKeyRequest) (*GetSshKeyResponse, error)
	// Node lifecycle
	DrainNode(context.Context, *DrainNodeRequest) (*DrainNodeResponse, error)
	ApproveNode(context.Context, *ApproveNodeRequest) (*ApproveNodeResponse, error)
	RejectNode(context.Context, *RejectNodeRequest) (*RejectNodeResponse, error)
	// Certificate rotation
	RenewNodeCert(context.Context, *RenewNodeCertRequest) (*RenewNodeCertResponse, error)
	// Bootstrap a node cert/key pair signed by controller sub-CA for fresh installs.
	IssueNodeBootstrapCert(context.Context, *IssueNodeBootstrapCertRequest) (*IssueNodeBootstrapCertResponse, error)
	RotateSubCa(context.Context, *RotateSubCaRequest) (*RotateSubCaResponse, error)
	ReloadTls(context.Context, *ReloadTlsRequest) (*ReloadTlsResponse, error)
	// Compliance
	GetComplianceReport(context.Context, *GetComplianceReportRequest) (*GetComplianceReportResponse, error)
	// Network overview: host interfaces from each node + default network config
	GetNetworkOverview(context.Context, *GetNetworkOverviewRequest) (*GetNetworkOverviewResponse, error)
	// Storage overview: cluster-wide VM data-plane backends (filesystem / LVM / ZFS), LUKS stats,
	// and per-node block inventory from each node agent (lsblk).
	GetStorageOverview(context.Context, *GetStorageOverviewRequest) (*GetStorageOverviewResponse, error)
	mustEmbedUnimplementedControllerServer()
}

